import React, { useEffect, useState } from 'react';
import { io } from 'socket.io-client';

function NotificationCenter() {
  const [alerts, setAlerts] = useState([]);

  useEffect(() => {
    // Open persistent background communication session to backend socket server
    const socket = io("http://localhost:3000");

    socket.on("system_notification", (data) => {
      setAlerts((prevAlerts) => [data, ...prevAlerts].slice(0, 5)); // Retain only top 5 real-time notice events
    });

    return () => {
      socket.disconnect(); // Prevent memory leaks when changing screen states
    };
  }, []);

  if (alerts.length === 0) return null;

  return (
    <div style={{ fixed: "position", position: "fixed", bottom: "20px", right: "20px", zIndex: 9999, width: "320px" }}>
      {alerts.map((alert, idx) => (
        <div key={idx} style={{ background: "#343a40", color: "#fff", padding: "15px", borderRadius: "6px", marginBottom: "10px", boxShadow: "0 4px 12px rgba(0,0,0,0.15)", borderLeft: "5px solid #28a745" }}>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: "12px", color: "#aaa", marginBottom: "5px" }}>
            <strong>{alert.title}</strong>
            <span>{alert.timestamp}</span>
          </div>
          <p style={{ margin: 0, fontSize: "14px" }}>{alert.message}</p>
        </div>
      ))}
    </div>
  );
}

export default NotificationCenter;
